using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class ProgressPhotoConfiguration : IEntityTypeConfiguration<ProgressPhoto>{public void Configure(EntityTypeBuilder<ProgressPhoto> builder){builder.ToTable("progress_photos");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("photo_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.PhotoUrl).IsRequired();builder.Property(e => e.StorageKey).IsRequired();builder.Property(e => e.Angle).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.Visibility).HasConversion<string>().HasMaxLength(20);builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.AssociatedMeasurement).WithMany().HasForeignKey(e => e.AssociatedMeasurementId);builder.HasQueryFilter(e => e.DeletedAt == null);builder.HasIndex(e => new { e.UserId, e.TakenAt });}}
